#include<iostream>#include<string>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        string x;        cin>>x;        bool flag=true;        if(n%2!=0){            if(x[0]=='b')flag=false;            else{                for(int i=1;i<n;i+=2){                    if(x[i]!='?' && x[i+1]!='?' && x[i]==x[i+1]){                        flag=false;                        break;                    }                                    }            }        }        else{            for(int i=0;i<n;i+=2){                if(x[i]!='?' && x[i+1]!='?' && x[i]==x[i+1]){                    flag=false;                    break;                }                            }        }        if(flag)cout<<"Yes\n";        else cout<<"No\n";    }}